// Get the input data
const input = $input.first();

// Try different ways to get the file content
let fileContent;

if (input.json && input.json.data) {
  fileContent = input.json.data;
} else if (input.binary && input.binary.data) {
  // If binary, convert to string
  const binaryData = input.binary.data;
  fileContent = Buffer.from(binaryData.data, 'base64').toString('utf8');
} else if (typeof input.json === 'string') {
  fileContent = input.json;
} else {
  throw new Error('Could not find file content. Input: ' + JSON.stringify(input));
}

console.log('File content type:', typeof fileContent);
console.log('File content preview:', fileContent.substring(0, 100));

const articles = JSON.parse(fileContent);

console.log('📊 Loaded articles from file:', articles.length);

// Return each article as separate item
return articles.map(article => ({
  json: article
}));

// Get all articles
const articles = $input.all().map(item => item.json);

// Filter criteria
const filtered = articles.filter(a => 
  a.body && 
  a.body.length > 100 && 
  a.body.length < 4000
);

console.log('📋 Total articles:', articles.length);
console.log('✅ Filtered articles:', filtered.length);

// Return filtered articles
return filtered.map(article => ({
  json: article
}));

// Collect all filtered articles
const articles = $input.all().map(item => item.json);

if (articles.length === 0) {
  console.log('⚠️ No articles to process');
  return [];
}

// Prepare batch request for LLM
const batchRequest = {
  request_id: `batch_${Date.now()}`,
  filters_used: {
    timeframe: "24h",
    source: "all"
  },
  articles: articles.map(a => ({
    id: a.id || `article_${Date.now()}_${Math.random()}`,
    title: a.title || "Untitled",
    body: a.body,
    language: a.language || "en",
    source: a.source,
    published_at: a.published_at
  }))
};

console.log('📦 Prepared batch with', batchRequest.articles.length, 'articles');
console.log('📝 Total characters:', batchRequest.articles.reduce((sum, a) => sum + a.body.length, 0));

return [{
  json: batchRequest
}];

const response = $input.first().json;

// Extract mega-summary
const summary = response.final_summary;
const articleCount = response.article_count;
const processedAt = response.processed_at;

console.log('✅ Summary received!');
console.log('📊 Articles processed:', articleCount);
console.log('📏 Summary length:', summary.length, 'chars');
console.log('🕐 Processed at:', processedAt);

// Format output
return [{
  json: {
    summary: summary,
    metadata: {
      request_id: response.request_id,
      article_count: articleCount,
      model: response.model,
      language: response.language,
      processed_at: processedAt,
      summary_length: summary.length
    },
    raw_response: response
  }
}];

const data = $input.first().json;

// Format for display/storage
const output = {
  title: `Mega Summary - ${data.metadata.article_count} Articles`,
  summary: data.summary,
  article_count: data.metadata.article_count,
  model: data.metadata.model,
  processed_at: data.metadata.processed_at,
  summary_length: data.metadata.summary_length
};

console.log('\n' + '='.repeat(60));
console.log('📰 MEGA SUMMARY COMPLETE');
console.log('='.repeat(60));
console.log(`Articles: ${output.article_count}`);
console.log(`Length: ${output.summary_length} characters`);
console.log(`Model: ${output.model}`);
console.log('='.repeat(60));
console.log('\nSUMMARY:');
console.log(output.summary);
console.log('\n' + '='.repeat(60));

return [{ json: output }];
